/**
 * FontPicker — Componente de seleção de fontes Google Fonts
 *
 * Exibe lista de fontes com preview em tempo real (cada nome renderizado
 * na própria fonte), busca por nome, seleção de weight e style, e
 * preview de texto customizado. Funções puras de filtragem e formatação
 * são exportadas para testes.
 */

'use client';

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Separator } from '@/components/ui/separator';
import { cn } from '@/lib/utils';
import { Type, Search, Check } from 'lucide-react';
import {
  type FontConfig,
  type FontFamily,
  type FontWeight,
  type FontStyleValue,
  POPULAR_FONTS,
  loadGoogleFont,
  searchFonts,
  getFallbackStack,
} from '@/lib/typography/font-manager';

// ─── Pure helpers (exportados para teste) ──────────────────────────

/**
 * Formata o peso da fonte para exibição legível.
 */
export function formatWeight(weight: FontWeight): string {
  const labels: Record<FontWeight, string> = {
    100: 'Thin',
    200: 'Extra Light',
    300: 'Light',
    400: 'Regular',
    500: 'Medium',
    600: 'Semi Bold',
    700: 'Bold',
    800: 'Extra Bold',
    900: 'Black',
  };
  return labels[weight] ?? String(weight);
}

/**
 * Gera o CSS font-family string para preview.
 */
export function buildPreviewFontFamily(family: string): string {
  return `"${family}", ${getFallbackStack(family)}`;
}

/**
 * Cria um FontConfig padrão a partir de uma FontFamily.
 */
export function createDefaultConfig(font: FontFamily): FontConfig {
  const defaultWeight: FontWeight = font.weights.includes(400) ? 400 : font.weights[0];
  return {
    family: font.family,
    weight: defaultWeight,
    style: 'normal' as FontStyleValue,
    size: 16,
    color: '#FFFFFF',
  };
}

// ─── Types ─────────────────────────────────────────────────────────

export interface FontPickerProps {
  /** Configuração de fonte selecionada atualmente */
  selectedFont?: FontConfig;
  /** Callback ao selecionar uma fonte */
  onFontSelect: (config: FontConfig) => void;
  /** Texto de preview customizado */
  previewText?: string;
  /** Classes CSS adicionais */
  className?: string;
}

// ─── Component ─────────────────────────────────────────────────────

export function FontPicker({
  selectedFont,
  onFontSelect,
  previewText = 'O rato roeu a roupa do rei de Roma',
  className,
}: FontPickerProps) {
  const [query, setQuery] = useState('');
  const [currentFont, setCurrentFont] = useState<FontConfig>(
    selectedFont ?? createDefaultConfig(POPULAR_FONTS[0]),
  );
  const [activeWeight, setActiveWeight] = useState<FontWeight>(currentFont.weight);
  const [activeStyle, setActiveStyle] = useState<FontStyleValue>(currentFont.style);

  // Sync external selection
  useEffect(() => {
    if (selectedFont) {
      setCurrentFont(selectedFont);
      setActiveWeight(selectedFont.weight);
      setActiveStyle(selectedFont.style);
    }
  }, [selectedFont]);

  const filteredFonts = useMemo(() => searchFonts(query), [query]);

  const selectedFamily = useMemo(
    () => POPULAR_FONTS.find((f) => f.family === currentFont.family),
    [currentFont.family],
  );

  const handleFontClick = useCallback(
    (font: FontFamily) => {
      loadGoogleFont(font.family, font.weights);
      const defaultWeight: FontWeight = font.weights.includes(activeWeight)
        ? activeWeight
        : font.weights.includes(400)
          ? 400
          : font.weights[0];

      const config: FontConfig = {
        family: font.family,
        weight: defaultWeight,
        style: activeStyle,
        size: currentFont.size,
        color: currentFont.color,
      };
      setCurrentFont(config);
      setActiveWeight(defaultWeight);
      onFontSelect(config);
    },
    [activeWeight, activeStyle, currentFont.size, currentFont.color, onFontSelect],
  );

  const handleWeightChange = useCallback(
    (weight: FontWeight) => {
      setActiveWeight(weight);
      const config: FontConfig = { ...currentFont, weight };
      setCurrentFont(config);
      onFontSelect(config);
    },
    [currentFont, onFontSelect],
  );

  const handleStyleToggle = useCallback(() => {
    const newStyle: FontStyleValue = activeStyle === 'normal' ? 'italic' : 'normal';
    setActiveStyle(newStyle);
    const config: FontConfig = { ...currentFont, style: newStyle };
    setCurrentFont(config);
    onFontSelect(config);
  }, [activeStyle, currentFont, onFontSelect]);

  return (
    <div
      className={cn(
        'flex flex-col gap-3 rounded-lg bg-zinc-900 p-4 border border-zinc-700',
        className,
      )}
    >
      {/* Header */}
      <div className="flex items-center gap-2 text-zinc-300">
        <Type className="h-4 w-4" />
        <Label className="text-sm font-medium">Fontes</Label>
      </div>

      {/* Search */}
      <div className="relative">
        <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-zinc-500" />
        <Input
          placeholder="Buscar fonte..."
          value={query}
          onChange={(e: React.ChangeEvent<HTMLInputElement>) => setQuery(e.target.value)}
          className="pl-9 bg-zinc-800 border-zinc-700 text-zinc-200 placeholder:text-zinc-500"
        />
      </div>

      {/* Font List */}
      <ScrollArea className="h-48 rounded-md border border-zinc-700">
        <div className="p-1">
          {filteredFonts.map((font) => {
            const isSelected = font.family === currentFont.family;
            return (
              <button
                key={font.family}
                type="button"
                onClick={() => handleFontClick(font)}
                className={cn(
                  'flex w-full items-center justify-between rounded-md px-3 py-2 text-left text-sm transition-colors',
                  isSelected
                    ? 'bg-zinc-700 text-white'
                    : 'text-zinc-300 hover:bg-zinc-800 hover:text-white',
                )}
              >
                <span
                  style={{
                    fontFamily: buildPreviewFontFamily(font.family),
                    fontWeight: 400,
                  }}
                >
                  {font.family}
                </span>
                {isSelected && <Check className="h-4 w-4 text-emerald-400" />}
              </button>
            );
          })}
          {filteredFonts.length === 0 && (
            <p className="px-3 py-4 text-center text-sm text-zinc-500">Nenhuma fonte encontrada</p>
          )}
        </div>
      </ScrollArea>

      <Separator className="bg-zinc-700" />

      {/* Weight selector */}
      {selectedFamily && (
        <div className="flex flex-col gap-2">
          <Label className="text-xs text-zinc-400">Peso</Label>
          <div className="flex flex-wrap gap-1">
            {selectedFamily.weights.map((w) => (
              <button
                key={w}
                type="button"
                onClick={() => handleWeightChange(w)}
                className={cn(
                  'rounded px-2 py-1 text-xs transition-colors',
                  w === activeWeight
                    ? 'bg-emerald-600 text-white'
                    : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700 hover:text-zinc-200',
                )}
              >
                {w}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Style toggle */}
      <div className="flex items-center gap-2">
        <Label className="text-xs text-zinc-400">Estilo</Label>
        <button
          type="button"
          onClick={handleStyleToggle}
          className={cn(
            'rounded px-3 py-1 text-xs transition-colors',
            activeStyle === 'italic'
              ? 'bg-emerald-600 text-white'
              : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700',
          )}
        >
          <span className={activeStyle === 'italic' ? 'italic' : ''}>Italic</span>
        </button>
      </div>

      <Separator className="bg-zinc-700" />

      {/* Preview */}
      <div className="flex flex-col gap-1">
        <Label className="text-xs text-zinc-400">Preview</Label>
        <div
          className="rounded-md bg-zinc-800 p-3 border border-zinc-700"
          style={{
            fontFamily: buildPreviewFontFamily(currentFont.family),
            fontWeight: activeWeight,
            fontStyle: activeStyle,
            fontSize: '18px',
            color: '#FFFFFF',
          }}
        >
          {previewText}
        </div>
      </div>
    </div>
  );
}

export default FontPicker;
